const { item_name, operation, quantity } = $json;
if (!item_name || !operation || !quantity) throw new Error('Missing fields');
return [{ json: { item_name, operation, quantity } }];

const stock = $json.stock_level || 0;
const qty = $json.quantity;
if (qty > stock) {
  return [{ json: { error: true, message: `Insufficient stock. Available: ${stock}` } }];
}
return items;
